"""Prior-session lookup tool for the Concierge router.

Gives the router a structured way to answer "pick up where we left off" without
hallucinating: it queries the DB for the most recent Concierge team session that
has non-empty workflow state for the current user.

The tool is intentionally read-only.  Rehydrating state into the current session
is left to the router — it can read the returned JSON and call update_workflow_state
if a resume is appropriate.
"""

from __future__ import annotations

import json
from typing import Any

from agno.db.base import SessionType
from agno.db.postgres import PostgresDb
from agno.run.base import RunContext
from agno.tools.decorator import tool
from agno.tools.toolkit import Toolkit

from agents.concierge.constants import CONCIERGE_TEAM_ID, WORKFLOW_STATE_SESSION_KEY
from agents.provisioner.constants import (
    SESSION_ENVIRONMENT_ID,
    SESSION_GITHUB_URL,
    SESSION_PROJECT_NAME,
    SESSION_TARGET_REPO_URL,
    SESSION_TMUX_SESSION_NAME,
    SESSION_USER_EMAIL,
)

_PROVISIONER_KEYS = (
    SESSION_ENVIRONMENT_ID,
    SESSION_GITHUB_URL,
    SESSION_PROJECT_NAME,
    SESSION_TARGET_REPO_URL,
    SESSION_TMUX_SESSION_NAME,
    SESSION_USER_EMAIL,
)


def _extract_cross_session_state(session_data: dict[str, Any] | None) -> dict[str, Any]:
    """Pull the keys from session_data that are meaningful across sessions."""
    if not session_data:
        return {}
    state: dict[str, Any] = session_data.get("session_state") or {}
    result: dict[str, Any] = {}
    workflow = state.get(WORKFLOW_STATE_SESSION_KEY)
    if workflow:
        result[WORKFLOW_STATE_SESSION_KEY] = workflow
    for key in _PROVISIONER_KEYS:
        value = state.get(key)
        if value:
            result[key] = value
    return result


def build_prior_session_toolkit(db: PostgresDb) -> Toolkit:
    """Return a toolkit scoped to ``db`` for looking up prior session context."""

    @tool(
        name="get_prior_workflow_state",
        description=(
            "Look up the most recent Concierge session state for the current user. "
            "Call this when the user says something like 'pick up where we left off' "
            "or 'continue from last time' AND the current session_state has no active "
            "or paused workflows. Returns the last known workflow goal, status, and "
            "provisioner context so you can answer specifically rather than asking the "
            "user to repeat themselves."
        ),
        requires_confirmation=False,
        stop_after_tool_call=False,
    )
    def get_prior_workflow_state(run_context: RunContext) -> str:  # noqa: WPS430
        user_id = run_context.user_id
        if not user_id:
            return json.dumps(
                {"found": False, "reason": "user_id is not set on this run; cannot query prior sessions"}
            )

        current_session_id = run_context.session_id
        try:
            raw_sessions, _ = db.get_sessions(  # type: ignore[misc]
                session_type=SessionType.TEAM,
                user_id=user_id,
                component_id=CONCIERGE_TEAM_ID,
                limit=5,
                sort_by="updated_at",
                sort_order="desc",
                deserialize=False,
            )
        except Exception as exc:
            return json.dumps({"found": False, "reason": f"db error: {exc}"})

        for row in raw_sessions:
            session_id = row.get("session_id")
            if session_id == current_session_id:
                continue
            session_data = row.get("session_data") or {}
            extracted = _extract_cross_session_state(session_data)
            if extracted:
                return json.dumps(
                    {
                        "found": True,
                        "prior_session_id": session_id,
                        "updated_at": row.get("updated_at"),
                        "state": extracted,
                    }
                )

        return json.dumps({"found": False, "reason": "no prior sessions with workflow context found for this user"})

    return Toolkit(
        name="prior_session_tools",
        tools=[get_prior_workflow_state],
        add_instructions=False,
    )

