"""Unit tests for Concierge memory manager and prior-session lookup tool."""

from __future__ import annotations

import json
from typing import cast
from unittest.mock import MagicMock, patch

import pytest
from agno.db.postgres import PostgresDb
from agno.memory.manager import MemoryManager
from agno.run.base import RunContext

from agents.concierge.memory import build_concierge_memory_manager
from agents.concierge.session_tools import _extract_cross_session_state, build_prior_session_toolkit
from agents.concierge.constants import WORKFLOW_STATE_SESSION_KEY
from agents.provisioner.constants import SESSION_PROJECT_NAME, SESSION_TARGET_REPO_URL


# ---------------------------------------------------------------------------
# memory manager
# ---------------------------------------------------------------------------


def test_build_concierge_memory_manager_returns_memory_manager() -> None:
    db = cast(PostgresDb, MagicMock())
    mm = build_concierge_memory_manager(db)
    assert isinstance(mm, MemoryManager)


def test_memory_manager_has_workflow_capture_instructions() -> None:
    db = cast(PostgresDb, MagicMock())
    mm = build_concierge_memory_manager(db)
    assert mm.memory_capture_instructions is not None
    assert "provisioning" in mm.memory_capture_instructions.lower()
    assert "workflow" in mm.memory_capture_instructions.lower()


def test_memory_manager_uses_provided_db() -> None:
    db = cast(PostgresDb, MagicMock())
    mm = build_concierge_memory_manager(db)
    assert mm.db is db


# ---------------------------------------------------------------------------
# _extract_cross_session_state
# ---------------------------------------------------------------------------


def _make_session_data(**state_keys) -> dict:
    return {"session_state": state_keys}


def test_extract_returns_empty_for_none() -> None:
    assert _extract_cross_session_state(None) == {}


def test_extract_returns_empty_for_empty_dict() -> None:
    assert _extract_cross_session_state({}) == {}


def test_extract_returns_empty_when_state_has_no_known_keys() -> None:
    data = _make_session_data(some_other_key="value")
    assert _extract_cross_session_state(data) == {}


def test_extract_captures_concierge_workflow() -> None:
    workflow = {"active_workflow": {"owner": "provisioner-agent", "status": "active", "goal": "Provision repo"}}
    data = _make_session_data(**{WORKFLOW_STATE_SESSION_KEY: workflow})
    result = _extract_cross_session_state(data)
    assert result[WORKFLOW_STATE_SESSION_KEY] == workflow


def test_extract_captures_provisioner_keys() -> None:
    data = _make_session_data(
        **{
            SESSION_PROJECT_NAME: "my-project",
            SESSION_TARGET_REPO_URL: "https://github.com/acme/api",
        }
    )
    result = _extract_cross_session_state(data)
    assert result[SESSION_PROJECT_NAME] == "my-project"
    assert result[SESSION_TARGET_REPO_URL] == "https://github.com/acme/api"


def test_extract_ignores_none_values() -> None:
    data = _make_session_data(**{SESSION_PROJECT_NAME: None, SESSION_TARGET_REPO_URL: "https://github.com/acme/api"})
    result = _extract_cross_session_state(data)
    assert SESSION_PROJECT_NAME not in result
    assert result[SESSION_TARGET_REPO_URL] == "https://github.com/acme/api"


# ---------------------------------------------------------------------------
# get_prior_workflow_state tool
# ---------------------------------------------------------------------------


def _make_run_context(user_id: str | None = "user-123", session_id: str = "session-current") -> RunContext:
    return RunContext(run_id="run-1", session_id=session_id, user_id=user_id)


def _make_toolkit(db: PostgresDb):
    return build_prior_session_toolkit(db)


def _call_tool(toolkit, run_context: RunContext) -> dict:
    fn = next(t for t in toolkit.tools if getattr(t, "name", None) == "get_prior_workflow_state")
    raw = fn.entrypoint(run_context)
    return json.loads(raw)


def test_tool_returns_not_found_when_no_user_id() -> None:
    db = cast(PostgresDb, MagicMock())
    toolkit = _make_toolkit(db)
    ctx = _make_run_context(user_id=None)
    result = _call_tool(toolkit, ctx)
    assert result["found"] is False
    assert "user_id" in result["reason"]


def test_tool_returns_not_found_when_db_has_no_prior_sessions() -> None:
    db = cast(PostgresDb, MagicMock())
    db.get_sessions.return_value = ([], 0)
    toolkit = _make_toolkit(db)
    ctx = _make_run_context()
    result = _call_tool(toolkit, ctx)
    assert result["found"] is False


def test_tool_skips_current_session() -> None:
    db = cast(PostgresDb, MagicMock())
    workflow = {"active_workflow": {"owner": "provisioner-agent", "status": "active", "goal": "Provision"}}
    db.get_sessions.return_value = (
        [
            {
                "session_id": "session-current",
                "session_data": {
                    "session_state": {WORKFLOW_STATE_SESSION_KEY: workflow}
                },
                "updated_at": 9999,
            }
        ],
        1,
    )
    toolkit = _make_toolkit(db)
    ctx = _make_run_context(session_id="session-current")
    result = _call_tool(toolkit, ctx)
    assert result["found"] is False


def test_tool_returns_prior_session_state() -> None:
    db = cast(PostgresDb, MagicMock())
    workflow = {"active_workflow": {"owner": "provisioner-agent", "status": "paused", "goal": "Provision repo X"}}
    db.get_sessions.return_value = (
        [
            {
                "session_id": "session-old",
                "session_data": {
                    "session_state": {
                        WORKFLOW_STATE_SESSION_KEY: workflow,
                        SESSION_PROJECT_NAME: "repo-x",
                    }
                },
                "updated_at": 1000,
            }
        ],
        1,
    )
    toolkit = _make_toolkit(db)
    ctx = _make_run_context(session_id="session-new")
    result = _call_tool(toolkit, ctx)
    assert result["found"] is True
    assert result["prior_session_id"] == "session-old"
    assert result["state"][WORKFLOW_STATE_SESSION_KEY] == workflow
    assert result["state"][SESSION_PROJECT_NAME] == "repo-x"


def test_tool_returns_not_found_when_prior_sessions_have_no_known_state() -> None:
    db = cast(PostgresDb, MagicMock())
    db.get_sessions.return_value = (
        [{"session_id": "session-old", "session_data": {"session_state": {"unrelated": "stuff"}}, "updated_at": 1}],
        1,
    )
    toolkit = _make_toolkit(db)
    ctx = _make_run_context(session_id="session-new")
    result = _call_tool(toolkit, ctx)
    assert result["found"] is False


def test_tool_handles_db_error_gracefully() -> None:
    db = cast(PostgresDb, MagicMock())
    db.get_sessions.side_effect = RuntimeError("connection refused")
    toolkit = _make_toolkit(db)
    ctx = _make_run_context()
    result = _call_tool(toolkit, ctx)
    assert result["found"] is False
    assert "db error" in result["reason"]

